53. 
54.     /// <inheritdoc />
55.     public string DateHumanize_Never() => "never";
56. 
57.     /// <inheritdoc />
58.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
59.     {
60.         var unit = GetUnitName(timeUnit, count);
61.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
62.     }
63. 
64.     private static string GetUnitName(TimeUnit timeUnit, int count)
65.     {
66.         var singular = timeUnit switch
67.         {
68.             TimeUnit.Year => "year",
69.             TimeUnit.Month => "month",
70.             TimeUnit.Day => "day",
71.             TimeUnit.Hour => "hour",
72.             TimeUnit.Minute => "minute",
73.             TimeUnit.Second => "second",
74.             _ => timeUnit.ToString().ToLowerInvariant()
75.         };
76. 
77.         return count != 1 ? singular + "s" : singular;
78.     }
79. 
80.     private static string NumberToWords(int number) =>
81.         number switch
82.         {
83.             1 => "one",
84.             2 => "two",
85.             3 => "three",
86.             _ => number.ToString()
87.         };
88. }
