292. /// <summary>
293. /// Strategies for humanizing date/time differences.
294. /// </summary>
295. public sealed class DefaultDateTimeHumanizeStrategy
296. {
297.     /// <summary>
298.     /// Humanizes a DateTime difference relative to a base date.
299.     /// </summary>
300.     /// <param name="input">The date to humanize.</param>
301.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
302.     /// <returns>A human-readable string representing the time difference.</returns>
303.     public string Humanize(DateTime input, DateTime comparedTo)
304.     {
305.         var difference = comparedTo - input;
306.         if (Math.Abs(difference.TotalSeconds) < 2)
307.         {
308.             return "just now";
309.         }
310. 
311.         var isFuture = difference.TotalSeconds < 0;
312.         var absDiff = difference.Duration();
313. 
314.         var result = absDiff.TotalDays switch
315.         {
316.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
317.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
318.             >= 1 => $"{(int)absDiff.TotalDays} days",
319.             _ => absDiff.TotalHours switch
320.             {
321.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
322.                 _ => absDiff.TotalMinutes switch
323.                 {
324.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
325.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
326.                 }
327.             }
328.         };
329. 
330.         return isFuture ? $"in {result}" : $"{result} ago";
331.     }
332. }
