             _ => timeUnit.ToString().ToLowerInvariant()
         };

         return count != 1 ? singular + "s" : singular;
     }

     private static string NumberToWords(int number) =>
         number switch
         {
             1 => "one",
             2 => "two",
             3 => "three",
             _ => number.ToString()
         };
 }

 /// <summary>
 /// German-specific formatter providing localized date/time humanization.
