 /// </summary>
 public sealed class RomanianOrdinalizer : DefaultOrdinalizer
 {
     /// <inheritdoc />
     public override string Convert(int number, string numberString)
     {
         // Complex Romanian ordinal logic
         if (number < 0)
         {
             return numberString;
         }

         return (number % 100) switch
         {
             1 => "primul",
             2 => "al doilea",
             _ => $"al {numberString}-lea"
         };
     }
 }

